SET LOCAL app.current_tenant_id = '{{ $json.tenantId }}';
UPDATE appointments
SET
  google_event_id = CASE
    WHEN '{{ $json.googleEventId }}' = '' THEN NULL
    ELSE '{{ $json.googleEventId }}'
  END,
  calendar_synced = {{ $json.calendarSynced }}
WHERE id = '{{ $json.appointmentId }}'::uuid;
